        &lt;xsl:apply-templates select="publication"/&gt;
      &lt;/body&gt;
    &lt;/html&gt;
  &lt;/xsl:template&gt;

  &lt;!-- ════════════════════════════════════════════════════ publication --&gt;
  &lt;xsl:template match="publication"&gt;
    &lt;h1&gt;&lt;xsl:value-of select="title"/&gt;&lt;/h1&gt;
    &lt;p class="pub-desc"&gt;&lt;xsl:value-of select="description"/&gt;&lt;/p&gt;
    &lt;xsl:apply-templates select="series"/&gt;
