XML Generation
Build the complete XML tree following the glossary.dtd structure: - &lt;glossary&gt; root with metadata and terms - Each &lt;term&gt; has name, optional also_known_as, definition, and series references - Series references include Wikibase QID attributes


Show code
def build_glossary_xml(df, glossary_id, title, version, source, date, description):
    """Build the complete &lt;glossary&gt; XML tree from the DataFrame.

    Args:
        df: DataFrame with CATEGORY, ALSO_KNOWN_AS, DEFINITION, SERIES_LIST columns
        glossary_id: Unique identifier for the glossary
        title, version, source, date, description: Metadata fields

    Returns:
        ElementTree root element
    """
    root = ET.Element('glossary', id=glossary_id)

    # ── Metadata ─────────────────────────────────────────────────────────────
    meta = ET.SubElement(root, 'metadata')
    ET.SubElement(meta, 'title').text = title
    ET.SubElement(meta, 'version').text = version
    ET.SubElement(meta, 'source').text = source
    ET.SubElement(meta, 'date').text = date
    if description:
        ET.SubElement(meta, 'description').text = description

    # ── Terms ────────────────────────────────────────────────────────────────
    terms_el = ET.SubElement(root, 'terms')

    for idx, row in df.iterrows():
        # Generate unique term ID (term_001, term_002, etc.)
        term_id = f'term_{idx+1:03d}'
        term_el = ET.SubElement(terms_el, 'term', id=term_id)

        # Name (required)
        ET.SubElement(term_el, 'name').text = row['CATEGORY']

        # Also known as (optional)
        if row['ALSO_KNOWN_AS'].strip():
            ET.SubElement(term_el, 'also_known_as').text = row['ALSO_KNOWN_AS']

        # Definition (required)
        ET.SubElement(term_el, 'definition').text = row['DEFINITION']

        # Series references
        series_list = row['SERIES_LIST']
        if series_list:
            series_el = ET.SubElement(term_el, 'series')
            for series_code in series_list:
                qid = SERIES_QID_MAP.get(series_code, '')
                if qid:
                    series_ref = ET.SubElement(series_el, 'series_ref', qid=qid)
                else:
                    series_ref = ET.SubElement(series_el, 'series_ref')
                series_ref.text = series_code
        else:
            # Empty series element for terms without series
            series_el = ET.SubElement(term_el, 'series')
            # Add a placeholder for terms without series
            series_ref = ET.SubElement(series_el, 'series_ref')
            series_ref.text = 'NONE'

    return root

print('XML generation function defined.')


